return [{ json: {
  product: 'ProjectFlow — project management SaaS',
  research_inputs: [
    { source: 'NPS survey (n=150)', findings: 'Two distinct groups: power users who use recurring tasks, dependencies, and bulk export daily; casual users who only create tasks and update status. The second group has high churn.' },
    { source: 'Customer interviews (n=12)', findings: 'PM personas: solo founders managing product + team, project leads at 20-50 person companies, enterprise PMs managing 5+ concurrent projects. Founders care about speed and mobile. Enterprise PMs care about integrations and reporting. Mid-market PMs care about team adoption and collaboration.' },
    { source: 'Segment analysis', findings: 'Segment A: 1-5 users, avg 8 tasks/week, 4-month LTV. Segment B: 6-20 users, avg 45 tasks/week, 14-month LTV. Segment C: 21-100 users, avg 200+ tasks/week, 24-month LTV.' },
    { source: 'Feature usage analytics', findings: 'Recurring tasks used by 28% of accounts but those accounts have 2× the NPS and 3× the retention. Dependencies used by 12% of accounts but all are in Segment C.' }
  ],
  segments_to_personas: 3,
  notes: 'Focus on actionable personas tied to retention and revenue. Avoid fictional detail — ground everything in research.'
} }];

const d = $input.first().json;
const inputText = d.research_inputs.map(r => `  Source: ${r.source}\n  Findings: ${r.findings}`).join('\n\n');
const system = `You are a UX researcher building evidence-based product personas. You ground every persona attribute in the provided research data — no fictional demographics. You focus on goals, frustrations, behaviours, and product implications. Return ONLY valid JSON.`;
const user = `Build ${d.segments_to_personas} product personas for: ${d.product}

Researcher note: ${d.notes}

Research inputs:
${inputText}

Return JSON:
{
  "personas": [
    {
      "name": "string — a memorable archetype name, not a fictional person",
      "archetype": "string — 1-2 word descriptor",
      "segment": "string — which user segment this persona represents",
      "primary_goal": "string",
      "secondary_goals": ["string"],
      "key_frustrations": ["string"],
      "behavioural_patterns": ["string — what they actually do in the product"],
      "success_metric": "string — how they define success",
      "retention_signal": "string — what predicts whether this persona stays or churns",
      "product_implications": ["string — what product decisions this persona drives"],
      "research_evidence": ["string — which research input supports this persona"]
    }
  ],
  "persona_matrix": "string — 2-3 sentence description of how the personas relate to each other"
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Persona Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.personas || !Array.isArray(parsed.personas)) return [{ json: { _error: true, reason: 'Missing personas' } }];
return [{ json: { _error: false, result: parsed, meta: { product: upstream.data.product, generated_at: new Date().toISOString() } } }];
